// Validate Calendly webhook signature
// Calendly signs payloads with HMAC-SHA256 using your webhook signing key
const crypto = require('crypto');

const signingKey = 'REPLACE_WITH_CALENDLY_SIGNING_KEY';
const rawBody = JSON.stringify($input.item.json.body || $input.item.json);
const receivedSignature = $input.item.json.headers?.['calendly-webhook-signature'] || '';

// Calendly signature format: "t=<timestamp>,v1=<signature>"
const parts = receivedSignature.split(',');
const timestampPart = parts.find(p => p.startsWith('t='));
const signaturePart = parts.find(p => p.startsWith('v1='));

if (!timestampPart || !signaturePart) {
  // If no signature header (e.g. in testing), allow through with a warning
  return [{ json: { ...($input.item.json), signatureValid: false, signatureSkipped: true } }];
}

const timestamp = timestampPart.replace('t=', '');
const receivedSig = signaturePart.replace('v1=', '');
const expectedSig = crypto
  .createHmac('sha256', signingKey)
  .update(`${timestamp}.${rawBody}`)
  .digest('hex');

const isValid = crypto.timingSafeEqual(
  Buffer.from(expectedSig, 'hex'),
  Buffer.from(receivedSig, 'hex')
);

if (!isValid) {
  throw new Error('Invalid Calendly webhook signature — request rejected.');
}

return [{ json: { ...($input.item.json), signatureValid: true } }];

// Gather all upstream data
const meeting = $('Extract Meeting Details').item.json;
const contact = $('HubSpot - Get Contact').item.json;
const dealsRaw = $('HubSpot - Get Open Deals').all();
const enrichment = $('Clearbit - Enrich Company').item.json;

const props = contact.properties || {};
const company = enrichment?.company || {};
const person = enrichment?.person || {};

// Format deals summary
const deals = dealsRaw
  .map(d => d.json?.properties)
  .filter(Boolean)
  .map(d => `• ${d.dealname || 'Unnamed deal'} — Stage: ${d.dealstage || 'N/A'} | Amount: $${d.amount || '0'} | Close: ${d.closedate ? new Date(d.closedate).toLocaleDateString() : 'N/A'} | Win prob: ${d.hs_deal_stage_probability ? Math.round(d.hs_deal_stage_probability * 100) + '%' : 'N/A'}`)
  .join('\n');

const contextForAI = `
Prospect: ${meeting.prospectName} (${meeting.prospectEmail})
Job Title: ${props.jobtitle || person.employment?.title || 'Unknown'}
Company: ${props.company || company.name || 'Unknown'}
Industry: ${company.category?.industry || 'Unknown'}
Company Size: ${company.metrics?.employees || 'Unknown'} employees
Estimated Revenue: ${company.metrics?.estimatedAnnualRevenue || 'Unknown'}
Lifecycle Stage: ${props.lifecyclestage || 'Unknown'}
Lead Status: ${props.hs_lead_status || 'Unknown'}
Open Deals:\n${deals || 'None found'}
Emails Opened: ${props.hs_email_open_count || '0'}
Last Reply: ${props.hs_sales_email_last_replied ? new Date(parseInt(props.hs_sales_email_last_replied)).toLocaleDateString() : 'Never'}
Meeting Type: ${meeting.meetingName}
`;

return [{ json: { contextForAI, meeting, props, company, person, deals, contactFound: true } }];

