`;

return [{ json: { contextForAI, meeting, company, props: {}, person: {}, deals: 'None — new prospect', contactFound: false } }];

const context = $('OpenAI - Generate Talking Points').item.json.choices?.[0]?.message?.content || '1. Research the prospect further before the call.\n2. Focus on discovery questions.\n3. Understand their current workflow before pitching.';

const data = $input.item.json;
const meeting = data.meeting;
const props = data.props || {};
const company = data.company || {};
const person = data.person || {};
const deals = data.deals || 'None';
const contactFound = data.contactFound;

const meetingDate = new Date(meeting.meetingTime).toLocaleString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  hour: '2-digit', minute: '2-digit', timeZoneName: 'short'
});

const crmSection = contactFound
  ? `━━━━━━━━━━━━━━━━━━━━━━━━
*👤 CRM Profile*
• Title: ${props.jobtitle || person.employment?.title || 'N/A'}
• Phone: ${props.phone || 'N/A'}
• Lifecycle Stage: ${props.lifecyclestage || 'N/A'}
• Lead Status: ${props.hs_lead_status || 'N/A'}
• Emails Opened: ${props.hs_email_open_count || '0'}
• Last Reply: ${props.hs_sales_email_last_replied ? new Date(parseInt(props.hs_sales_email_last_replied)).toLocaleDateString() : 'Never'}

━━━━━━━━━━━━━━━━━━━━━━━━
*💼 Open Deals*
${typeof deals === 'string' ? deals : deals || 'None found'}`
  : `⚠️ *New prospect — not in CRM yet. Add them after the call.*`;

const prepPack = `*📋 Pre-Meeting Prep Pack*
*Meeting:* ${meeting.meetingName}
*When:* ${meetingDate}
*Prospect:* ${meeting.prospectName} (${meeting.prospectEmail})

━━━━━━━━━━━━━━━━━━━━━━━━
*🏢 Company Overview*
• Company: ${props.company || company.name || 'Unknown'}
• Industry: ${company.category?.industry || 'N/A'}
• Employees: ${company.metrics?.employees || 'N/A'}
• Revenue: ${company.metrics?.estimatedAnnualRevenue || 'N/A'}
• Location: ${[company.geo?.city, company.geo?.country].filter(Boolean).join(', ') || 'N/A'}

${crmSection}

━━━━━━━━━━━━━━━━━━━━━━━━
*🤖 AI Talking Points*
${context}

━━━━━━━━━━━━━━━━━━━━━━━━
_Prep pack auto-generated by n8n • ${new Date().toLocaleString()}_`;

return [{ json: { prepPack, prospectName: meeting.prospectName, prospectEmail: meeting.prospectEmail, meetingTime: meeting.meetingTime, meetingName: meeting.meetingName, meetingUuid: meeting.meetingUuid, salesRepEmail: meeting.salesRepEmail, eventUri: meeting.eventUri, contactFound, talkingPoints: context } }];
